import{_ as a,o as s,c as i,ag as e}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"세션 프루닝","description":"컨텍스트를 간결하게 유지하고 캐싱 효율을 높이기 위해 오래된 도구 결과 정리","frontmatter":{"title":"세션 프루닝","description":"컨텍스트를 간결하게 유지하고 캐싱 효율을 높이기 위해 오래된 도구 결과 정리"},"headers":[],"relativePath":"concepts/session-pruning.md","filePath":"concepts/session-pruning.md","lastUpdated":null}'),n={name:"concepts/session-pruning.md"};function l(o,t,d,r,h,p){return s(),i("div",null,[...t[0]||(t[0]=[e(`<h1 id="세션-프루닝" tabindex="-1">세션 프루닝 <a class="header-anchor" href="#세션-프루닝" aria-label="Permalink to &quot;세션 프루닝&quot;">​</a></h1><p>세션 프루닝은 각 LLM 호출 전에 컨텍스트에서 <strong>오래된 도구 결과</strong>를 정리합니다. 일반 대화 텍스트를 다시 쓰지 않고 누적된 도구 출력 (exec 결과, 파일 읽기, 검색 결과)으로 인한 컨텍스트 비대화를 줄입니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>프루닝은 인메모리 전용입니다 -- 디스크의 세션 트랜스크립트를 수정하지 않습니다. 전체 히스토리는 항상 보존됩니다.</p></div><h2 id="중요한-이유" tabindex="-1">중요한 이유 <a class="header-anchor" href="#중요한-이유" aria-label="Permalink to &quot;중요한 이유&quot;">​</a></h2><p>긴 세션은 컨텍스트 창을 팽창시키는 도구 출력을 누적합니다. 이는 비용을 증가시키고 필요 이상으로 일찍 <a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a>을 강제할 수 있습니다.</p><p>프루닝은 <strong>Anthropic 프롬프트 캐싱</strong>에 특히 유용합니다. 캐시 TTL이 만료된 후, 다음 요청은 전체 프롬프트를 다시 캐시합니다. 프루닝은 캐시 쓰기 크기를 줄여 비용을 직접 낮춥니다.</p><h2 id="작동-방식" tabindex="-1">작동 방식 <a class="header-anchor" href="#작동-방식" aria-label="Permalink to &quot;작동 방식&quot;">​</a></h2><ol><li>캐시 TTL이 만료될 때까지 기다립니다 (기본값 5분).</li><li>일반 프루닝을 위한 오래된 도구 결과를 찾습니다 (대화 텍스트는 그대로 유지됨).</li><li><strong>소프트 정리</strong> 과도한 크기의 결과 -- 헤드와 테일을 유지하고 <code>...</code>를 삽입합니다.</li><li><strong>하드 클리어</strong> 나머지 -- 플레이스홀더로 대체합니다.</li><li>TTL을 재설정하여 후속 요청이 새 캐시를 재사용하도록 합니다.</li></ol><h2 id="레거시-이미지-정리" tabindex="-1">레거시 이미지 정리 <a class="header-anchor" href="#레거시-이미지-정리" aria-label="Permalink to &quot;레거시 이미지 정리&quot;">​</a></h2><p>OpenClaw는 또한 히스토리에 원시 이미지 블록을 유지했던 오래된 레거시 세션에 대해 별도의 멱등성 정리를 실행합니다.</p><ul><li><strong>가장 최근 3개의 완료된 턴</strong>을 바이트 단위로 보존하여 최근 후속 조치의 프롬프트 캐시 접두사가 안정적으로 유지됩니다.</li><li><code>user</code> 또는 <code>toolResult</code> 히스토리의 오래된 이미 처리된 이미지 블록은 <code>[image data removed - already processed by model]</code>로 대체될 수 있습니다.</li><li>이는 일반 캐시-TTL 프루닝과 별개입니다. 반복된 이미지 페이로드가 나중 턴에서 프롬프트 캐시를 무효화하는 것을 방지하기 위해 존재합니다.</li></ul><h2 id="스마트-기본값" tabindex="-1">스마트 기본값 <a class="header-anchor" href="#스마트-기본값" aria-label="Permalink to &quot;스마트 기본값&quot;">​</a></h2><p>OpenClaw는 Anthropic 프로필에 대해 프루닝을 자동으로 활성화합니다:</p><table tabindex="0"><thead><tr><th>프로필 유형</th><th>프루닝 활성화</th><th>하트비트</th></tr></thead><tbody><tr><td>Anthropic OAuth/토큰 인증 (Claude CLI 재사용 포함)</td><td>예</td><td>1시간</td></tr><tr><td>API 키</td><td>예</td><td>30분</td></tr></tbody></table><p>명시적인 값을 설정하면 OpenClaw는 이를 오버라이드하지 않습니다.</p><h2 id="활성화-또는-비활성화" tabindex="-1">활성화 또는 비활성화 <a class="header-anchor" href="#활성화-또는-비활성화" aria-label="Permalink to &quot;활성화 또는 비활성화&quot;">​</a></h2><p>프루닝은 비Anthropic 프로바이더에 대해 기본값으로 꺼져 있습니다. 활성화하려면:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      contextPruning</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cache-ttl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ttl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;5m&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>비활성화하려면: <code>mode: &quot;off&quot;</code>를 설정하십시오.</p><h2 id="프루닝-대-컴팩션" tabindex="-1">프루닝 대 컴팩션 <a class="header-anchor" href="#프루닝-대-컴팩션" aria-label="Permalink to &quot;프루닝 대 컴팩션&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>프루닝</th><th>컴팩션</th></tr></thead><tbody><tr><td><strong>대상</strong></td><td>도구 결과 정리</td><td>대화 요약</td></tr><tr><td><strong>저장</strong></td><td>아니오 (요청별)</td><td>예 (트랜스크립트에)</td></tr><tr><td><strong>범위</strong></td><td>도구 결과만</td><td>전체 대화</td></tr></tbody></table><p>이 둘은 서로 보완적입니다 -- 프루닝은 컴팩션 사이클 사이에 도구 출력을 간결하게 유지합니다.</p><h2 id="추가-읽기" tabindex="-1">추가 읽기 <a class="header-anchor" href="#추가-읽기" aria-label="Permalink to &quot;추가 읽기&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a> -- 요약 기반 컨텍스트 축소</li><li><a href="/openclaw-docs-ko/gateway/configuration">게이트웨이 구성</a> -- 모든 프루닝 구성 설정 (<code>contextPruning.*</code>)</li></ul>`,24)])])}const E=a(n,[["render",l]]);export{k as __pageData,E as default};
